	}

	// audit sinks configuration
	sinks := make([]audit.Sink, 0)

	if cfg.Audit.Sinks.LogFile.Enabled {
		logFileSink, err := logfile.NewSink(logger, cfg.Audit.Sinks.LogFile.File)
		if err != nil {
